function parseEvent(json) {
  const data = JSON.parse(json);
  const known = {
    userId: data.user_id || null,
    eventTime: data.event_time || null,
    country: data.country || null
  };
  const extraKeys = Object.keys(data).filter(k => !(k in known));
  const extra = JSON.stringify(extraKeys.reduce((acc, k) => { acc[k] = data[k]; return acc; }, {}));
  return { ...known, extra_json: extra };
}
```

